function addToFavorites(element,productId){if(!element)return;const isCurrentlyFav="true"===element.getAttribute("data-favorite"),url=isCurrentlyFav?element.getAttribute("data-remove-url"):element.getAttribute("data-add-url"),tokenElement=document.querySelector('input[name="__RequestVerificationToken"]');if(!tokenElement)return void console.error("Token bulunamadı!");const token=tokenElement.value;element.disabled=!0,fetch(url,{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded",RequestVerificationToken:token},body:`productId=${productId}`}).then((response=>{if(response.ok){const nextState=!isCurrentlyFav;element.setAttribute("data-favorite",nextState?"true":"false"),element.setAttribute("data-tooltip",nextState?"Favorilerden Çıkar":"Favorilere Ekle");const solid=element.querySelector(".fa-solid.fa-heart"),regular=element.querySelector(".fa-regular.fa-heart");if(solid&&regular&&(solid.style.display=nextState?"inline-block":"none",regular.style.display=nextState?"none":"inline-block"),isCurrentlyFav&&window.location.pathname.toLowerCase().includes("favoriler")){let card=element.closest(".col-6, .col-md-4, .col-xl-3");card&&(card.style.transition="opacity 0.3s",card.style.opacity=0,setTimeout((()=>card.remove()),300))}}else alert("İşlem gerçekleştirilemedi. Lütfen giriş yaptığınızdan emin olun.")})).catch((error=>{console.error("Hata:",error)})).finally((()=>{element.disabled=!1}))}